import React from "react";

export default function Orders() {
  const hasOrders = false;
  return (
    <div className="page-container">
      <h2>Your Orders</h2>
      {hasOrders ? (
        <p>Here are your recent orders.</p>
      ) : (
        <p>No orders placed yet.</p>
      )}
    </div>
  );
}
